30	  static readonly textTertiary: string = 'rgba(15,51,41,0.56)';
31	  static readonly textQuaternary: string = 'rgba(15,51,41,0.46)';
32	  static readonly textPlaceholder: string = 'rgba(15,51,41,0.38)';
33	  static readonly borderDefault: string = '#D9CFC4';
34	  static readonly borderSoft: string = 'rgba(15,51,41,0.08)';
35	  static readonly cardDivider: string = '#E6DCD3';
36	  static readonly chipSelectedStart: string = '#E8F3F0';
37	  static readonly chipSelectedEnd: string = '#D4E9E2';
38	  static readonly chipSoftBg: string = '#F6F1EA';
39	  static readonly calorieTagBg: string = '#F6F1EA';
40	  static readonly calorieTagText: string = '#5C4033';
