// Template snippet for generated ArkTS apps.
// Copy and adapt field names and save behavior. Do not import this file directly.

@Component
export struct EditableTitleSection {
  @State private showEditorSheet: boolean = false
  @State private draftTitle: string = ''
  @Prop currentTitle: string = ''
  onSave: (title: string) => void = () => {}

  @Builder
  EditorSheet() {
    Column({ space: 12 }) {
      TextInput({ text: this.draftTitle })
        .id('editor-title-input')
        .onChange((value: string) => {
          this.draftTitle = value
        })
      Button('Save')
        .id('editor-save-button')
        .onClick(() => {
          this.onSave(this.draftTitle.trim())
          this.showEditorSheet = false
        })
    }
    .padding(20)
  }

  build() {
    Button('Edit')
      .onClick(() => {
        this.draftTitle = this.currentTitle
        this.showEditorSheet = true
      })
      .bindSheet(this.showEditorSheet, this.EditorSheet(), {
        preferType: SheetType.BOTTOM,
        onWillDisappear: () => {
          this.showEditorSheet = false
        }
      })
  }
}

