// Template snippet for generated ArkTS apps.
// Copy and adapt model, repository, events, and methods. Do not import this file directly.

@Observed
export class ItemListState {
  items: ItemModel[] = []
  filteredItems: ItemModel[] = []
  selectedFilter: string = 'all'
  isLoading: boolean = false
  errorMessage: string = ''
}

export class ItemListViewModel {
  readonly state: ItemListState = new ItemListState()
  private repository: ItemRepository

  constructor(repository: ItemRepository) {
    this.repository = repository
  }

  async load(): Promise<void> {
    this.state.isLoading = true
    this.state.errorMessage = ''
    try {
      this.state.items = await this.repository.list()
      this.applyFilter()
    } catch (_) {
      this.state.errorMessage = 'Load failed'
    }
    this.state.isLoading = false
  }

  setFilter(filter: string): void {
    this.state.selectedFilter = filter
    this.applyFilter()
  }

  private applyFilter(): void {
    this.state.filteredItems = this.repository.filter(this.state.items, this.state.selectedFilter)
  }
}

export enum Gender {
  MALE = 'male',
  FEMALE = 'female',
  UNKNOWN = 'unknown'
}

@Observed
export class Pet {
  id: string = ''
  name: string = ''
  avatar: string = ''
  species: string = ''
  breed: string = ''
  birthday: string = ''
  gender: Gender = Gender.UNKNOWN
  weight: number = 0
  neutered: boolean = false
  medicalHistory: string = ''

  constructor(id: string, name: string) {
    this.id = id
    this.name = name
  }
}

export enum FamilyRole {
  OWNER = 'owner',
  MEMBER = 'member'
}

@Observed
export class FamilyMember {
  id: string = ''
  nickname: string = ''
  role: FamilyRole = FamilyRole.MEMBER
  avatar: string = ''
}

@Observed
export class FamilyGroup {
  id: string = ''
  name: string = ''
  inviteCode: string = ''
  members: FamilyMember[] = []

  constructor(id: string, name: string, inviteCode: string) {
    this.id = id
    this.name = name
    this.inviteCode = inviteCode
  }
}

export class ChartPoint {
  dateLabel: string = ''
  value: number = 0
}

export class ChartInsight {
  summary: string = ''
  changePercent: number | null = null
  trend: 'up' | 'down' | 'flat' = 'flat'
}

export type ChartMetric = 'weight' | 'food' | 'waste' | 'medicine'

export type ChartPeriod = 'week' | 'month'

