              .fontSize(14)
              .fontColor(Theme.textTertiary)
              .width('100%')
              .textAlign(TextAlign.Center)
              .padding({ top: 60, bottom: 60 })
          }
        } else {
          ForEach(this.state.pets, (pet: Pet, index: number) => {
            ListItem() {
              Row({ space: 14 }) {
                Column() {
                  SvgIcon({ variant: index % 2 === 0 ? 'avatar-1' : 'avatar-2', iconSize: 28 })
