import { AppState } from '../viewmodel/AppViewModel'
import { Theme } from '../common/Theme'
import { Reminder } from '../models/Reminder'
import { Pet } from '../models/Pet'
import { Repository } from '../service/Repository'

interface RemindersPageProps {
  state: AppState
  repository: Repository
  onBack: () => void
  onOpenReminderEditor: (reminderId?: string, petId?: string) => void
}

@Component
export struct RemindersPage {
  @ObjectLink state: AppState
  repository: Repository = new Repository({} as unknown as import('../service/Store').JsonPreferenceStore)
  onBack: () => void = () => {}
  onOpenReminderEditor: (reminderId?: string, petId?: string) => void = () => {}

  private filteredReminders(): Reminder[] {
    if (this.state.reminderFilterStatus === 'all') {
      return this.state.reminders.slice()
    }
    return this.state.reminders.filter((r: Reminder) => this.repository.reminderStatus(r) === this.state.reminderFilterStatus)
  }

  private petName(petId: string): string {
    return this.state.pets.find((p: Pet) => p.id === petId)?.name ?? ''
  }

  private statusStyle(status: 'due' | 'upcoming' | 'normal') {
    if (status === 'due') {
      return { label: '逾期', bg: Theme.statusOverdueBg, text: Theme.statusOverdueText, border: Theme.statusOverdue }
    }
    if (status === 'upcoming') {
      return { label: '即将到期', bg: Theme.statusSoonBg, text: Theme.statusSoonText, border: Theme.statusSoon }
    }
    return { label: '正常', bg: Theme.statusOkBg, text: Theme.statusOkText, border: Theme.statusOk }
  }

  build() {
    Column({ space: 0 }) {
      Row() {
        Text('<')
          .fontSize(22)
          .fontColor(Theme.textSecondary)
          .onClick(() => this.onBack())
        Text('提醒管理')
          .fontSize(18)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textPrimary)
        Text('添加')
          .id('reminders-add-button')
          .fontSize(14)
          .fontColor(Theme.brandPrimary)
          .onClick(() => this.onOpenReminderEditor(undefined, this.state.selectedPetId))
      }
      .width('100%')
      .justifyContent(FlexAlign.SpaceBetween)
      .alignItems(VerticalAlign.Center)
      .margin({ top: 24, bottom: 16 })

      Select([
        { value: '全部', icon: undefined },
        { value: '逾期', icon: undefined },
        { value: '即将到期', icon: undefined },
        { value: '正常', icon: undefined }
      ])
        .id('reminders-filter-status')
        .selected(this.statusIndex())
        .onSelect((index: number) => {
          const statuses: ('all' | 'due' | 'upcoming' | 'normal')[] = ['all', 'due', 'upcoming', 'normal']
          this.state.reminderFilterStatus = statuses[index]
        })
        .margin({ bottom: 16 })

      List({ space: 12 }) {
        if (this.filteredReminders().length === 0) {
          ListItem() {
            Text('暂无提醒')
              .id('reminders-empty')
              .fontSize(14)
              .fontColor(Theme.textTertiary)
              .width('100%')
              .textAlign(TextAlign.Center)
              .padding({ top: 60, bottom: 60 })
          }
        } else {
          ForEach(this.filteredReminders(), (r: Reminder) => {
            const st = this.statusStyle(this.repository.reminderStatus(r))
            ListItem() {
              Row({ space: 12 }) {
                Column({ space: 2 }) {
                  Text(`${this.petName(r.petId)} · ${r.title}`)
                    .fontSize(15)
                    .fontWeight(FontWeight.Medium)
                    .fontColor(Theme.textSecondary)
                  Text(`到期日 ${r.dueDate}`)
                    .fontSize(12)
                    .fontColor(Theme.textTertiary)
                }
                .layoutWeight(1)
                .alignItems(HorizontalAlign.Start)

                Toggle({ type: ToggleType.Switch, isOn: r.enabled })
                  .id(`reminders-item-${r.id}-toggle`)
                  .selectedColor(Theme.brandPrimary)
                  .onChange((isOn: boolean) => {
                    r.enabled = isOn
                  })

                Text(st.label)
                  .fontSize(11)
                  .fontWeight(FontWeight.Medium)
                  .fontColor(st.text)
                  .backgroundColor(st.bg)
                  .padding({ left: 8, right: 8, top: 4, bottom: 4 })
                  .borderRadius(8)
              }
              .width('100%')
              .padding(14)
              .backgroundColor(Theme.cardBg)
              .borderRadius(16)
              .border({ width: { left: 4 }, color: { left: st.border } })
            }
            .id(`reminders-item-${r.id}`)
            .onClick(() => this.onOpenReminderEditor(r.id))
          }, (r: Reminder) => r.id)
        }
      }
      .id('reminders-list')
      .width('100%')
      .layoutWeight(1)
      .scrollBar(BarState.Off)
    }
    .id('reminders-page')
    .width('100%')
    .height('100%')
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
    .constraintSize({ maxWidth: Theme.contentMaxWidth })
    .backgroundColor(Theme.pageBg)
  }

  private statusIndex(): number {
    const s = this.state.reminderFilterStatus
    if (s === 'all') return 0
    if (s === 'due') return 1
    if (s === 'upcoming') return 2
    return 3
  }
}

